import{_ as e}from"./chunks/demo-doc.NIuiqrK9.js";import{c as o,Q as c,j as t,m as a}from"./chunks/framework.BkjtU8k0.js";const x=JSON.parse('{"title":"支持格式","description":"","frontmatter":{},"headers":[],"relativePath":"guide/formats.md","filePath":"guide/formats.md","lastUpdated":1779763590000}'),i={name:"guide/formats.md"};function l(r,d,s,h,n,p){return c(),t("div",null,[...d[0]||(d[0]=[a('<h1 id="支持格式" tabindex="-1">支持格式 <a class="header-anchor" href="#支持格式" aria-label="Permalink to &quot;支持格式&quot;">​</a></h1><div class="doc-kicker">Runtime Truth</div><p class="doc-lead"> 当前版本内置 <strong>135 个扩展名映射</strong>，覆盖 <strong>19 条预览链路</strong>。 这一页不是“计划支持什么”，而是以当前代码里已经注册好的渲染器为准，告诉你项目现在到底能处理哪些格式、分别走哪条渲染链路，以及在真实业务里应该怎么选。 </p><div class="doc-grid"><div class="doc-card"><h3>135 个扩展名映射</h3><p>覆盖 Office、PDF、OFD、压缩包、邮件、OLB/DRA、CAD、3D 模型、Excalidraw、draw.io、EPUB、UMD、Markdown、图片、音频、代码/文本和视频等常见附件类型。</p></div><div class="doc-card"><h3>按需异步加载</h3><p>OFD、压缩包、邮件、OLB/DRA、CAD、3D 模型、绘图、PDF、Office、Markdown、代码高亮等渲染器都会拆成独立异步块，命中格式时才加载。</p></div><div class="doc-card"><h3>两条输入路径</h3><p>既可以用 <code>url</code> 直接预览，也可以在业务侧拿到文件后二次包装成 <code>File</code> 再传入。</p></div><div class="doc-card"><h3>以体验边界为准</h3><p>不同格式会走不同解析链路，兼容优先的格式与高保真格式在样式还原上并不完全一样。</p></div></div><h2 id="当前支持矩阵" tabindex="-1">当前支持矩阵 <a class="header-anchor" href="#当前支持矩阵" aria-label="Permalink to &quot;当前支持矩阵&quot;">​</a></h2><table tabindex="0"><thead><tr><th>分类</th><th>扩展名</th><th>渲染链路</th><th>当前表现</th><th>更适合的场景</th></tr></thead><tbody><tr><td>Word</td><td><code>docx</code></td><td><code>docx-preview</code></td><td>白色纸张显示在灰色页面底中，支持宽度自适应和长文档视觉分页</td><td>新生成的 Word 文档、正式公文、模板文档</td></tr><tr><td>Word</td><td><code>doc</code></td><td><code>msdoc-viewer</code></td><td>使用 Word 风格页面容器，页面居中显示在灰色工作台中</td><td>存量老文档、历史附件回溯</td></tr><tr><td>Excel</td><td><code>xlsx</code></td><td><code>styled-exceljs</code> + <code>e-virt-table</code></td><td>支持虚拟滚动、列宽/行高、合并单元格和常见样式</td><td>大表格预览、报表、需要保留结构和样式的业务</td></tr><tr><td>Excel 兼容格式</td><td><code>xlsm</code>、<code>xlsb</code>、<code>xls</code>、<code>csv</code>、<code>ods</code>、<code>fods</code>、<code>numbers</code></td><td><code>styled-exceljs</code> + <code>e-virt-table</code></td><td>统一读取数据、尺寸和可用样式，按浏览器能力渐进还原</td><td>老表格、跨平台导出的表格、轻量数据查看</td></tr><tr><td>PowerPoint</td><td><code>pptx</code></td><td>自定义 PPTX 渲染器</td><td>以页面展示为主，增强组合图形、旋转/翻转、主题背景、图片裁剪和 EMF 矢量图预览</td><td>汇报材料、说明文档、培训课件</td></tr><tr><td>PDF</td><td><code>pdf</code></td><td><code>pdfjs-dist</code></td><td>浏览器端 PDF 渲染，支持缩放工具栏、页码状态和可显隐导航窗格</td><td>合同、票据、版式稳定文件</td></tr><tr><td>OFD</td><td><code>ofd</code></td><td><code>DLTech21/ofd.js</code> 源码</td><td>使用浏览器端 OFD 解析和页面渲染，避开 npm dist 授权 wasm 分支</td><td>电子发票、公文、国产版式归档材料</td></tr><tr><td>压缩包</td><td><code>zip</code>、<code>zipx</code>、<code>7z</code>、<code>rar</code>、<code>tar</code>、<code>gz</code>、<code>gzip</code>、<code>tgz</code>、<code>bz2</code>、<code>bzip2</code>、<code>tbz</code>、<code>tbz2</code>、<code>xz</code>、<code>txz</code>、<code>lzma</code>、<code>zst</code>、<code>tzst</code>、<code>cab</code>、<code>ar</code>、<code>cpio</code>、<code>iso</code>、<code>xar</code>、<code>lha</code>、<code>lzh</code>、<code>jar</code>、<code>war</code>、<code>ear</code>、<code>apk</code>、<code>cbz</code>、<code>cbr</code></td><td><code>libarchive.js</code> + WASM Worker</td><td>先读取目录，点击文件后按需解压；内部文件继续复用统一预览器，并支持 IndexedDB 缓存和体积上限</td><td>归档附件、批量交付包、压缩包内文档快速查看</td></tr><tr><td>邮件</td><td><code>eml</code>、<code>msg</code></td><td><code>postal-mime</code> / <code>@kenjiuno/msgreader</code></td><td>展示头信息、HTML/文本正文、附件列表；附件可下载，也可继续在线预览</td><td>邮件归档、客服工单、客户来信附件</td></tr><tr><td>EDA</td><td><code>olb</code>、<code>dra</code></td><td><code>cfb</code> 容器解析 + 二进制字符串索引</td><td>优先解析 OrCAD / Allegro 常见 CFB 容器，展示内部条目、文本片段和可读字符串；非 CFB 文件安全退化</td><td>元件库、封装图纸、EDA 文件初筛</td></tr><tr><td>CAD</td><td><code>dxf</code></td><td><code>@cadview/core</code></td><td>Canvas 方式浏览 DXF 图纸，支持缩放、平移、图层显示控制</td><td>工程图纸、二维 CAD 附件</td></tr><tr><td>CAD 兼容入口</td><td><code>dwg</code></td><td>DWG 兼容解析</td><td>先识别误命名 DXF；真实 DWG 会尽量提取内嵌 PNG/JPEG/BMP 预览图，无法完整解析几何时说明原因</td><td>需要兼容上传入口但不希望引入 GPL 或闭源 DWG 运行时代码的业务</td></tr><tr><td>3D 模型</td><td><code>glb</code>、<code>gltf</code>、<code>obj</code>、<code>stl</code>、<code>ply</code>、<code>fbx</code>、<code>dae</code>、<code>3ds</code>、<code>3mf</code>、<code>amf</code>、<code>usd</code>、<code>usda</code>、<code>usdc</code>、<code>usdz</code>、<code>kmz</code>、<code>pcd</code>、<code>wrl</code>、<code>vrml</code>、<code>xyz</code>、<code>vtk</code>、<code>vtp</code>、<code>step</code>、<code>stp</code>、<code>iges</code>、<code>igs</code>、<code>ifc</code>、<code>3dm</code></td><td>Three.js</td><td>WebGL 交互预览，支持轨道控制、适配视图、网格/坐标轴、线框和自动旋转；工程 CAD/BIM 格式会给出转换原因</td><td>设计模型、点云、三维资产、工程模型</td></tr><tr><td>Excalidraw</td><td><code>excalidraw</code></td><td><code>@excalidraw/excalidraw</code></td><td>使用官方 <code>restore</code> 兼容真实公开文件，再通过 <code>exportToSvg</code> 输出只读 SVG 预览</td><td>白板草图、产品沟通图、流程草稿</td></tr><tr><td>draw.io</td><td><code>drawio</code>、<code>dio</code></td><td>diagrams.net <code>GraphViewer</code></td><td>使用官方 viewer 渲染 mxGraphModel / mxfile，不自行解析 draw.io 方言</td><td>流程图、架构图、业务泳道图</td></tr><tr><td>电子书</td><td><code>epub</code></td><td><code>epubjs</code></td><td>解析 EPUB 包、目录和章节资源，使用滚动阅读避免超宽分页白板</td><td>电子书、培训手册、长篇阅读材料</td></tr><tr><td>电子书</td><td><code>umd</code></td><td>UMD 结构解析 + <code>pako</code></td><td>解析老移动电子书的元数据、章节偏移、章节标题和 zlib 压缩正文</td><td>历史小说附件、旧移动阅读文件</td></tr><tr><td>Markdown</td><td><code>md</code>、<code>markdown</code></td><td>Markdown 渲染器</td><td>保留 Markdown 阅读样式</td><td>README、知识文档、开发说明</td></tr><tr><td>图片</td><td><code>gif</code>、<code>jpg</code>、<code>jpeg</code>、<code>bmp</code>、<code>tiff</code>、<code>tif</code>、<code>png</code>、<code>svg</code>、<code>webp</code></td><td>图片渲染器</td><td>原生图片浏览</td><td>图片附件、设计稿、截图、Logo</td></tr><tr><td>代码/文本</td><td><code>txt</code>、<code>json</code>、<code>js</code>、<code>mjs</code>、<code>cjs</code>、<code>css</code>、<code>java</code>、<code>py</code>、<code>html</code>、<code>htm</code>、<code>jsx</code>、<code>ts</code>、<code>tsx</code>、<code>xml</code>、<code>log</code>、<code>vue</code>、<code>yaml</code>、<code>yml</code>、<code>ini</code>、<code>sh</code>、<code>bash</code>、<code>sql</code>、<code>go</code>、<code>rs</code>、<code>php</code>、<code>c</code>、<code>cpp</code>、<code>cc</code>、<code>h</code>、<code>hpp</code>、<code>cs</code>、<code>diff</code></td><td><code>highlight.js</code></td><td>按源码方式展示并轻量高亮，不执行脚本</td><td>配置文件、日志、代码片段、接口响应</td></tr><tr><td>音频</td><td><code>mp3</code>、<code>mpeg</code>、<code>wav</code>、<code>ogg</code>、<code>oga</code>、<code>opus</code>、<code>m4a</code>、<code>aac</code>、<code>flac</code>、<code>weba</code></td><td>浏览器原生 <code>&lt;audio&gt;</code></td><td>使用原生音频控件播放，具体编码支持取决于浏览器</td><td>录音、播客、语音附件、音效素材</td></tr><tr><td>视频</td><td><code>mp4</code></td><td>浏览器原生视频播放器</td><td>原生播放、带控制条</td><td>演示视频、录屏材料</td></tr></tbody></table><h2 id="按类型看体验和边界" tabindex="-1">按类型看体验和边界 <a class="header-anchor" href="#按类型看体验和边界" aria-label="Permalink to &quot;按类型看体验和边界&quot;">​</a></h2><h3 id="word-文档" tabindex="-1">Word 文档 <a class="header-anchor" href="#word-文档" aria-label="Permalink to &quot;Word 文档&quot;">​</a></h3><ul><li><code>docx</code> 使用 <code>docx-preview</code>，适合正文、表格、图片和常规版式较多的现代 Word 文档。当前预览层会恢复白色纸张和灰色页面底，并根据可用宽度自动缩放。</li><li><code>doc</code> 使用 <code>msdoc-viewer</code>，并额外套用 Word 风格页面容器。它不只是“把内容吐出来”，而是尽量保留文档阅读时的页面感。</li><li>如果源文档缺少显式分页，<code>.docx</code> 预览会在浏览器端补一层视觉分页，避免长文档变成一整条没有纸张边界的内容流。</li><li>如果你的业务能控制导出格式，优先推荐 <code>docx</code>；如果你面对的是存量老文档，当前 <code>.doc</code> 已经可以作为正式能力对外说明。</li></ul><div class="doc-shot"><img src="'+e+'" alt="DOC 文档按 Word 风格展示"><p class="doc-caption">`.doc` 文件现在会显示在灰色工作台中的白色纸张上，页面居中，阅读路径更接近真实 Word 阅读体验。</p></div><h3 id="表格类文件" tabindex="-1">表格类文件 <a class="header-anchor" href="#表格类文件" aria-label="Permalink to &quot;表格类文件&quot;">​</a></h3><ul><li>表格类文件统一走 <code>styled-exceljs</code> 解析和 <code>e-virt-table</code> 虚拟渲染，适合需要保留表格结构、合并单元格和视觉层级的场景。</li><li><code>xlsm</code>、<code>xlsb</code>、<code>xls</code>、<code>csv</code>、<code>ods</code>、<code>fods</code>、<code>numbers</code> 会读取格式中能表达的数据、尺寸和样式；部分格式本身不包含完整样式时，会按可用信息渐进还原。</li><li>如果你正在设计业务导出格式，优先选 <code>xlsx</code>；如果你只是需要把历史附件打开看内容，兼容链路已经足够实用。</li></ul><h3 id="演示文稿、pdf-与-ofd" tabindex="-1">演示文稿、PDF 与 OFD <a class="header-anchor" href="#演示文稿、pdf-与-ofd" aria-label="Permalink to &quot;演示文稿、PDF 与 OFD&quot;">​</a></h3><ul><li><code>pptx</code> 适合浏览幻灯片内容、做方案回看和日常演示，不需要 Office 本体参与。</li><li>PPTX 渲染器现在会按 DrawingML 的组合图形坐标系处理 <code>chOff/chExt</code>，组合内元素在缩放、旋转、翻转时会更接近 PowerPoint 中的位置关系。</li><li>主题背景支持从 <code>fillStyleLst</code> / <code>bgFillStyleLst</code> 解析纯色、渐变、图片和平铺图案；PPTX 内嵌的 EMF 图片会尽量转换为 SVG 数据图，避免只显示空白占位。</li><li>图片填充会处理 <code>srcRect</code> 裁剪信息，复杂模板里的裁切图、背景图和组合形状更适合作为真实业务样本回归。</li><li><code>pdf</code> 走 <code>pdfjs-dist</code>，通常是版式最稳定的一类文件，适合合同、流程单、正式成品材料。当前 PDF 视图提供顶部缩放工具栏、页码状态和可显隐页面导航窗格。</li><li><code>ofd</code> 走 <code>DLTech21/ofd.js</code> 仓库源码，用于国产版式文档在线预览。npm dist 当前会在 wasm 解析层返回授权错误，组件改用同仓库的纯 JS 解析/渲染链路，OFD 依赖仍保持按需异步加载。</li><li>如果你更在意“展示结果必须完全稳定”，优先考虑 <code>pdf</code> / <code>ofd</code> 这类版式成品；如果你需要保留可编辑文件的阅读入口，优先用 <code>pptx</code>。</li></ul><h3 id="压缩包、邮件与-eda" tabindex="-1">压缩包、邮件与 EDA <a class="header-anchor" href="#压缩包、邮件与-eda" aria-label="Permalink to &quot;压缩包、邮件与 EDA&quot;">​</a></h3><ul><li>压缩包走 <code>libarchive.js</code>，目录读取在 Worker 中完成，只有用户点击内部文件时才按需解压对应条目，避免一次性把大包全量展开到主线程。</li><li>压缩包内文件会继续复用同一套文件预览器，所以包里的 PDF、Word、Markdown、代码、图片、邮件或嵌套压缩包都能在体积限制内继续打开。</li><li><code>options.archive.cache</code> 默认启用 IndexedDB 缓存，已解压的内部文件再次打开会更快；<code>maxArchiveSize</code> 和 <code>maxEntryPreviewSize</code> 用于限制压缩包和单个条目的内存风险。</li><li>EML 使用 <code>postal-mime</code> 解析 MIME、正文和附件；MSG 使用 <code>@kenjiuno/msgreader</code> 解析 Outlook MSG，附件同样支持下载和在线预览。</li><li>邮件 HTML 正文渲染在 sandbox iframe 中，不执行脚本；如果你接收外部邮件，仍建议在业务层保留病毒扫描和附件白名单策略。</li><li>OLB / DRA 使用 <code>cfb</code> 读取常见复合文档容器，适合在线查看内部条目和可读属性。复杂电气规则、封装编辑和几何校核仍应交给 OrCAD / Allegro 等专业工具。</li></ul><h3 id="cad-图纸" tabindex="-1">CAD 图纸 <a class="header-anchor" href="#cad-图纸" aria-label="Permalink to &quot;CAD 图纸&quot;">​</a></h3><ul><li><code>dxf</code> 走 <code>@cadview/core</code>，提供 Canvas 图纸预览、缩放、平移和图层显隐能力。</li><li><code>dwg</code> 当前会尽量处理: 如果文件内容其实是 DXF 文本，会直接按 DXF 打开；如果是真 DWG 二进制，会扫描并提取内嵌 PNG/JPEG/BMP 预览图。</li><li>真实 DWG 的矢量图元、图层、块参照和实体几何仍不能在纯 Apache-2.0 前端包里完整解析。原因是 DWG 为专有二进制格式，常见开源转换器授权与当前包不匹配，闭源 SDK 又不适合直接打进 npm 包。</li><li>如果你要在生产系统里稳定预览 CAD 文件，建议把 DXF 作为前端预览标准格式；若必须接收 DWG，建议在上传或归档环节接入私有服务端转换链路。</li></ul><h3 id="_3d-模型" tabindex="-1">3D 模型 <a class="header-anchor" href="#_3d-模型" aria-label="Permalink to &quot;3D 模型&quot;">​</a></h3><ul><li>3D 模型统一走 Three.js，组件会根据扩展名按需加载对应 loader，避免普通文档预览被 3D 依赖拖慢。</li><li><code>glb</code> / <code>gltf</code> 是最推荐的 Web 3D 交换格式；<code>obj</code>、<code>stl</code>、<code>ply</code> 适合轻量几何和打印模型；<code>fbx</code>、<code>dae</code>、<code>3ds</code>、<code>3mf</code>、<code>amf</code>、<code>usd</code> / <code>usdz</code>、<code>kmz</code> 适合兼容设计工具导出的历史或工程资产。</li><li><code>pcd</code>、<code>xyz</code>、<code>vtk</code>、<code>vtp</code> 会按点云或几何模型展示，适合扫描、仿真和工程数据的快速浏览。</li><li><code>step</code> / <code>stp</code>、<code>iges</code> / <code>igs</code>、<code>ifc</code>、<code>3dm</code> 已保留入口，但完整解析需要 OpenCascade、web-ifc 或 rhino3dm 这类 WebAssembly 几何内核；组件会展示原因，生产建议在私有服务端转换为 <code>glb</code> / <code>gltf</code>。</li><li>如果 <code>.gltf</code>、<code>.dae</code>、<code>.fbx</code> 依赖同目录贴图、材质或 <code>.bin</code> 文件，使用 <code>url</code> 远程预览时会以原始 URL 的目录作为资源基准继续加载；使用本地单文件上传时，请优先选择 <code>.glb</code> 或把资源内联。</li></ul><h3 id="绘图文件" tabindex="-1">绘图文件 <a class="header-anchor" href="#绘图文件" aria-label="Permalink to &quot;绘图文件&quot;">​</a></h3><ul><li><code>excalidraw</code> 使用官方 <code>@excalidraw/excalidraw</code> 包的 <code>restore</code> 与 <code>exportToSvg</code> 能力，按需加载后输出只读 SVG 预览，不手写 Excalidraw 图元解析器。</li><li><code>drawio</code> 和 <code>dio</code> 使用官方 diagrams.net <code>GraphViewer</code>，由官方 viewer 处理 mxGraphModel / mxfile、主题和图元兼容，组件只负责创建容器和传入 XML。</li><li>draw.io viewer 脚本来自 diagrams.net 官方静态地址，只有命中 <code>.drawio</code> / <code>.dio</code> 时才加载；需要内网私有化时，可以把该官方脚本镜像到自己的静态资源域名再替换加载地址。</li></ul><h3 id="电子书" tabindex="-1">电子书 <a class="header-anchor" href="#电子书" aria-label="Permalink to &quot;电子书&quot;">​</a></h3><ul><li><code>epub</code> 使用 <code>epubjs</code>，由成熟开源库处理 EPUB zip 包、OPF、目录和章节资源。</li><li>EPUB 预览提供目录窗格、上一章/下一章式导航和阅读进度。正文区域使用滚动文档模式，避免部分浏览器在超宽分页 iframe 下出现白板。为了安全，阅读器不会允许书内脚本执行。</li><li><code>umd</code> 是早期移动阅读器常见的电子书封装。当前没有可靠维护的前端 UMD 阅读库，组件按公开文件结构解析文件头、元数据、章节偏移、章节标题和正文数据块，正文 zlib 解压交给 <code>pako</code>。</li><li>UMD 文本正文按 UTF-16LE 解码，保留章节目录和换行；图片/漫画类 UMD 会尽量按图像数据块展示，但复杂混排文件建议用真实样本补充回归。</li><li>Kindle 专有格式、DRM 电子书或业务加密包不在当前内置范围内，建议在接入侧转换为 EPUB、UMD 文本电子书或 PDF 后预览。</li></ul><h3 id="markdown、代码与文本" tabindex="-1">Markdown、代码与文本 <a class="header-anchor" href="#markdown、代码与文本" aria-label="Permalink to &quot;Markdown、代码与文本&quot;">​</a></h3><ul><li><code>md</code> 和 <code>markdown</code> 会按 Markdown 阅读样式展示，适合项目说明、知识文档和内部手册。</li><li>代码和文本文件会使用 <code>highlight.js</code> 做轻量高亮，按扩展名匹配语言，不命中时会自动退回纯文本。</li><li>这里有一个很重要的边界：<code>html</code> 文件会被当作源码看，而不是在预览器里当网页执行。这是更安全、也更可控的默认策略。</li></ul><h3 id="图片、音频与视频" tabindex="-1">图片、音频与视频 <a class="header-anchor" href="#图片、音频与视频" aria-label="Permalink to &quot;图片、音频与视频&quot;">​</a></h3><ul><li>图片类支持 <code>gif</code>、<code>jpg</code>、<code>jpeg</code>、<code>bmp</code>、<code>tiff</code>、<code>tif</code>、<code>png</code>、<code>svg</code>、<code>webp</code>。</li><li><code>svg</code> 会作为图片来展示，很适合拿来放矢量图标、流程图和品牌素材。</li><li>音频类支持 <code>mp3</code>、<code>mpeg</code>、<code>wav</code>、<code>ogg</code>、<code>oga</code>、<code>opus</code>、<code>m4a</code>、<code>aac</code>、<code>flac</code>、<code>weba</code>，使用浏览器原生播放器；不同浏览器对编码格式的支持会有差异。</li><li>视频当前支持 <code>mp4</code>，使用浏览器原生播放器，适合最常见的演示和录屏场景。</li></ul><h2 id="真实业务里怎么选" tabindex="-1">真实业务里怎么选 <a class="header-anchor" href="#真实业务里怎么选" aria-label="Permalink to &quot;真实业务里怎么选&quot;">​</a></h2><ul><li>你能控制导出格式：优先使用 <code>docx</code>、<code>xlsx</code>、<code>pptx</code>、<code>pdf</code>、<code>ofd</code>、<code>dxf</code>、<code>glb</code> 这类现代或稳定交换格式。</li><li>你要兼容历史附件：<code>.doc</code> 与 <code>xls/xlsm/xlsb/csv/ods</code> 这一组已经有正式链路，但要接受它们与现代格式在样式上的差异。</li><li>你要看日志、配置或代码：直接用代码/文本链路即可，重点是快速打开、检索内容和保持安全。</li><li>你在做品牌、示意图或视觉素材展示：<code>png</code>、<code>svg</code>、<code>webp</code> 这类图片格式会比转成文档更省心。</li><li>你要预览 CAD：优先沉淀 <code>dxf</code>；<code>dwg</code> 可以展示内嵌预览图，但完整几何预览建议转换为 DXF。</li><li>你要预览 3D 模型：优先沉淀 <code>glb</code> / <code>gltf</code>，历史模型再用 OBJ、STL、PLY、FBX、DAE、3DS、3MF、AMF、USD/USDZ、KMZ 等格式接入；STEP、IGES、IFC、3DM 建议先转换。</li><li>你要预览绘图文件：Excalidraw 和 draw.io 都保留源格式入口，前者走官方恢复与导出 SVG，后者走官方 diagrams.net viewer。</li><li>你要预览电子书或音频：EPUB / UMD 优先保留源文件，音频优先选择浏览器兼容最稳定的 MP3 / OGG。</li></ul><h2 id="不支持的格式会怎样" tabindex="-1">不支持的格式会怎样 <a class="header-anchor" href="#不支持的格式会怎样" aria-label="Permalink to &quot;不支持的格式会怎样&quot;">​</a></h2><p>如果文件扩展名没有命中已注册渲染器，组件会显示“不支持当前格式在线预览”的提示，引导用户下载后查看或转换格式。</p><div class="doc-note"> 最稳妥的做法，不是只看这张表，而是把你业务里最关键的那几类真实文件各准备一份样本，走一遍本地 Demo 和接入页联调。这样你拿去对外说明时，底气会更足。 </div>',33)])])}const b=o(i,[["render",l]]);export{x as __pageData,b as default};
